import{_ as a,o as s,c as t,ag as i}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"Tauri Monorepo Plan","description":"","frontmatter":{},"headers":[],"relativePath":"plans/tauri-monorepo.md","filePath":"plans/tauri-monorepo.md","lastUpdated":null}'),o={name:"plans/tauri-monorepo.md"};function n(r,e,l,p,h,c){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="tauri-monorepo-plan" tabindex="-1">Tauri Monorepo Plan <a class="header-anchor" href="#tauri-monorepo-plan" aria-label="Permalink to &quot;Tauri Monorepo Plan&quot;">​</a></h1><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>xAI and OpenAI APIs don&#39;t support CORS — can&#39;t call them directly from the browser. Venice and OpenRouter work as proxies but are intermediaries.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Migrate to a monorepo: web PWA + Tauri desktop app sharing the same codebase. Desktop app uses Rust to bypass CORS, enabling direct xAI/OpenAI/Google AI access.</p><h2 id="phased-approach" tabindex="-1">Phased Approach <a class="header-anchor" href="#phased-approach" aria-label="Permalink to &quot;Phased Approach&quot;">​</a></h2><h3 id="phase-1-tauri-wrapper-2-3-sessions-—-do-this-first" tabindex="-1">Phase 1: Tauri Wrapper (2-3 sessions) — do this first <a class="header-anchor" href="#phase-1-tauri-wrapper-2-3-sessions-—-do-this-first" aria-label="Permalink to &quot;Phase 1: Tauri Wrapper (2-3 sessions) — do this first&quot;">​</a></h3><ul><li>Wrap existing vanilla JS app in Tauri webview (no UI rewrite)</li><li>Add Rust commands to proxy API calls (bypasses CORS)</li><li>Unlock xAI, OpenAI, Google AI as direct providers in desktop app</li><li>GitHub Actions CI builds for Mac, Windows, Linux</li><li>Auto-updates via Tauri&#39;s built-in updater</li><li>Web version at getbased.health stays unchanged</li><li>~5% ongoing overhead (Rust function per new provider, automated release builds)</li></ul><h3 id="phase-2-svelte-ui-migration-10-15-sessions-—-later" tabindex="-1">Phase 2: Svelte UI Migration (10-15 sessions) — later <a class="header-anchor" href="#phase-2-svelte-ui-migration-10-15-sessions-—-later" aria-label="Permalink to &quot;Phase 2: Svelte UI Migration (10-15 sessions) — later&quot;">​</a></h3><ul><li>Extract schema, constants, data pipeline, API layer to <code>packages/shared</code> as TypeScript</li><li>Rewrite UI modules as Svelte components (views.js, chat.js, pdf-import.js, settings.js, context-cards.js, emf.js are the big ones)</li><li>Each ~500-1500 lines of innerHTML/DOM manipulation → reactive Svelte components</li></ul><h3 id="phase-3-sveltekit-web-1-2-sessions-—-last" tabindex="-1">Phase 3: SvelteKit Web (1-2 sessions) — last <a class="header-anchor" href="#phase-3-sveltekit-web-1-2-sessions-—-last" aria-label="Permalink to &quot;Phase 3: SvelteKit Web (1-2 sessions) — last&quot;">​</a></h3><ul><li>Replace vanilla JS web version with SvelteKit static build using the Svelte components from Phase 2</li></ul><h2 id="monorepo-structure" tabindex="-1">Monorepo Structure <a class="header-anchor" href="#monorepo-structure" aria-label="Permalink to &quot;Monorepo Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>packages/</span></span>
<span class="line"><span>  shared/     — TS types, schema, constants, data pipeline</span></span>
<span class="line"><span>  ui/         — Svelte components (charts, modals, cards, chat)</span></span>
<span class="line"><span>  web/        — SvelteKit static PWA</span></span>
<span class="line"><span>  desktop/    — Tauri (Rust backend + same Svelte UI)</span></span></code></pre></div><h2 id="when-to-start" tabindex="-1">When to Start <a class="header-anchor" href="#when-to-start" aria-label="Permalink to &quot;When to Start&quot;">​</a></h2><ul><li><strong>Phase 1</strong>: After current feature wave settles (recommendations shipped, Jonseed feedback addressed, i18n queued). Clean 2-3 session project.</li><li><strong>Phase 2</strong>: When vanilla JS actively blocks a feature. Trigger points: <ul><li>i18n gets painful (string interpolation in innerHTML)</li><li>Cross-device sync needs proper state management</li><li>Module count passes ~35 and window.* coupling hurts maintenance</li></ul></li><li><strong>Phase 3</strong>: Once Svelte components are mature enough to replace vanilla JS web version.</li></ul><h2 id="desktop-app-benefits" tabindex="-1">Desktop App Benefits <a class="header-anchor" href="#desktop-app-benefits" aria-label="Permalink to &quot;Desktop App Benefits&quot;">​</a></h2><ul><li>Direct xAI, OpenAI, Google AI (no CORS)</li><li>Native keychain for API keys (not localStorage)</li><li>Real filesystem backup (no File System Access API permission dance)</li><li>Background sync potential</li><li>Smaller attack surface</li><li>Taskbar/dock presence, auto-updates, no browser chrome</li></ul><h2 id="key-insight" tabindex="-1">Key Insight <a class="header-anchor" href="#key-insight" aria-label="Permalink to &quot;Key Insight&quot;">​</a></h2><p>Phase 1 is additive — no rewrite risk, minimal overhead. The vanilla JS app is still the prototype; every feature shipped now teaches what the real data flow should be. Rewrite when &quot;I can&#39;t do X&quot; not &quot;it would be cleaner.&quot;</p>`,20)])])}const m=a(o,[["render",n]]);export{u as __pageData,m as default};
